import{_ as a,a as t,b as s,c as i,d as n,e as o}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as d,o as l,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"IP Geolocation او User Management","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Other/ip-geolocation-and-user-management.md","filePath":"ps/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"ps/Other/ip-geolocation-and-user-management.md"};function u(g,e,h,m,b,f){return l(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocation-او-user-management" tabindex="-1">IP Geolocation او User Management <a class="header-anchor" href="#ip-geolocation-او-user-management" aria-label="Permalink to &quot;IP Geolocation او User Management&quot;">​</a></h1><p>IP geolocation د uploader records، login devices او ورته logs کې IP addresses تقریبي locations ته اړوي.</p><p>له تنظیم وروسته، admin panel د upload او access origins روښانه ښودلای شي. User Management هم تاسې ته اجازه درکوي چې د suspicious IP addresses upload access block یا restore کړئ.</p><h2 id="چېرته-یې-تنظیم-کړئ" tabindex="-1">چېرته یې تنظیم کړئ <a class="header-anchor" href="#چېرته-یې-تنظیم-کړئ" aria-label="Permalink to &quot;چېرته یې تنظیم کړئ&quot;">​</a></h2><p>دا پرانیزئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="شته-settings" tabindex="-1">شته Settings <a class="header-anchor" href="#شته-settings" aria-label="Permalink to &quot;شته Settings&quot;">​</a></h2><p>نوی IP geolocation flow د یوې map service پر ځای څو sources ملاتړ کوي.</p><table tabindex="0"><thead><tr><th>Setting</th><th>موخه</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>display language ټاکي، لکه English، Simplified Chinese، Japanese، French او نور.</td></tr><tr><td>MaxMind Account ID</td><td>د MaxMind GeoLite Web Service لپاره MaxMind account ID.</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key.</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key. د Chinese addresses او mainland China IPs لپاره ګټور دی.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. multilingual IP geolocation ملاتړ کوي.</td></tr></tbody></table><p>یوازې هغه services ډک کړئ چې اړتیا ورته لرئ. هر field تنظیمول اړین نه دي.</p><p>که key ورنه کړل شي، ImgBed لا هم built-in free sources هڅوي، خو stability، language support او precision ښايي له هغه service کم وي چې خپله یې configure کوئ.</p><h2 id="سپارښتل-شوي-انتخابونه" tabindex="-1">سپارښتل شوي انتخابونه <a class="header-anchor" href="#سپارښتل-شوي-انتخابونه" aria-label="Permalink to &quot;سپارښتل شوي انتخابونه&quot;">​</a></h2><p>که تاسې عموما Chinese addresses ته اړتیا لرئ:</p><ol><li>IP geolocation language پر Simplified Chinese وټاکئ.</li><li>Tencent Map Key تنظیم کړئ.</li><li>MaxMind یا ipapi د fallback sources په توګه optionally اضافه کړئ.</li></ol><p>که English یا multilingual addresses ته اړتیا لرئ:</p><ol><li>هغه language وټاکئ چې اړتیا ورته لرئ.</li><li>MaxMind Account ID او License Key تنظیم کړئ.</li><li>که ښه multilingual results غواړئ، ipapi Key اضافه کړئ.</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind دې ته اړتیا لري:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>account ID په MaxMind dashboard کې ومومئ او License Key د License Keys page څخه generate کړئ.</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>له generation وروسته، Account ID او License Key په ImgBed کې paste او save کړئ.</p><p>د MaxMind free plan د ورځني استعمال لپاره مناسب دی، خو request limits لري. که quota واوړي، ImgBed نور available sources هڅوي.</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi د APILayer API Key کاروي.</p><p>ipapi console پرانیزئ او هلته ښکاره API Key copy کړئ.</p><p><img src="'+s+'" alt="ipapi config" loading="lazy"></p><p>په ImgBed کې یې د <code>ipapi Key</code> field ته paste او save کړئ.</p><p>ipapi multilingual IP geolocation ملاتړ کوي او هغه وخت ګټور دی چې addresses په ټاکلې language کې ښودل غواړئ. free plan یې هم request limits لري. که quota خلاصه شي، ImgBed نور available sources هڅوي.</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key د Chinese addresses لپاره ګټور دی، په ځانګړي ډول mainland China IPs.</p><p>کله چې په Tencent Location Service کې key جوړوئ، دا enable کړئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>له جوړېدو وروسته، key په <code>Tencent Map Key</code> کې paste او save کړئ.</p><p>که یوازې basic Chinese IP geolocation ته اړتیا لرئ، Tencent Map Key د پیل لپاره بس دی.</p><h2 id="په-user-management-کې-څه-وګورئ" tabindex="-1">په User Management کې څه وګورئ <a class="header-anchor" href="#په-user-management-کې-څه-وګورئ" aria-label="Permalink to &quot;په User Management کې څه وګورئ&quot;">​</a></h2><p>User Management د admin panel له سر څخه available دی.</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management د IP له مخې upload activity ښيي:</p><table tabindex="0"><thead><tr><th>Field</th><th>تشریح</th></tr></thead><tbody><tr><td>IP source</td><td>د uploader source IP.</td></tr><tr><td>Address</td><td>له IP څخه resolved تقریبي location.</td></tr><tr><td>Total upload size</td><td>د دې IP له خوا uploaded ټول file size.</td></tr><tr><td>Upload count</td><td>له دې IP څخه د uploads شمېر.</td></tr><tr><td>Upload allowed</td><td>On یعنې uploads allowed دي. Off یعنې uploads blocked دي.</td></tr></tbody></table><p>د چپ arrow کلیک کړئ څو د هغه IP له خوا uploaded files list expand شي.</p><p>file list د file name، preview، file size، moderation result، file status او upload time ښيي. که uploads suspicious ښکاري، لومړی IP expand کړئ، files وګورئ، بیا پرېکړه وکړئ چې نور uploads block کړئ که نه.</p><p>که IP suspicious وي، <code>Upload allowed</code> off کړئ. راتلونکي uploads له هماغه IP څخه block کېږي.</p><h2 id="search،-sort-او-advanced-filters" tabindex="-1">Search، Sort او Advanced Filters <a class="header-anchor" href="#search،-sort-او-advanced-filters" aria-label="Permalink to &quot;Search، Sort او Advanced Filters&quot;">​</a></h2><p>د User Management په سر کې د IP source یا address له مخې search وکړئ.</p><p>د time، upload count یا total upload size له مخې sort وکړئ، څو recent uploaders، high-frequency uploaders یا high-usage IPs ومومئ.</p><p>د ژور investigation لپاره advanced filters پرانیزئ.</p><p><img src="'+n+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters ملاتړ کوي:</p><table tabindex="0"><thead><tr><th>Filter</th><th>کارونه</th></tr></thead><tbody><tr><td>Time range</td><td>هغه IPs ښيي چې په ټاکلې موده کې یې files upload کړي وي.</td></tr><tr><td>Access status</td><td>د normal، blocked او ورته states له مخې filter کوي.</td></tr><tr><td>Allow/block list</td><td>د allowlist، blocklist یا unset له مخې filter کوي.</td></tr><tr><td>File type</td><td>هغه IPs ښيي چې images، videos، audio، documents، code یا نور files یې upload کړي وي.</td></tr><tr><td>File size</td><td>د uploaded file size range له مخې filter کوي.</td></tr><tr><td>Age rating</td><td>د unset، General، R12+، R16+، R18 او ورته ratings له مخې filter کوي.</td></tr><tr><td>File status</td><td>د اوسني file status له مخې filter کوي، څو abnormal files وڅېړئ.</td></tr></tbody></table><p><code>Apply Filters</code> کلیک کړئ څو apply شي. <code>Reset</code> وکاروئ څو ټول data ته بېرته وګرځئ.</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>په mobile کې User Management card layout ته بدلېږي.</p><p><img src="'+o+`" alt="Mobile user management" loading="lazy"></p><p>هر card IP، address، total upload size، upload count او upload allowed switch ښيي. د horizontal table scrolling پرته users manage کولای شئ.</p><h2 id="که-location-غلط-ښکاري" tabindex="-1">که Location غلط ښکاري <a class="header-anchor" href="#که-location-غلط-ښکاري" aria-label="Permalink to &quot;که Location غلط ښکاري&quot;">​</a></h2><p>IP geolocation تقریبي دی. دا دقیق street address نه دی.</p><p>که user د proxy، data center، cloud server یا cross-border network تر شا وي، ښودل شوی location له اصلي location سره توپیر لرلای شي.</p><p>دا feature د rough origin درک، abnormal uploads موندلو او blocking decisions سره د مرستې لپاره وکاروئ. د precise tracking په توګه یې مه ګڼئ.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>معنا</th></tr></thead><tbody><tr><td>Address تش دی</td><td>IP ښايي لا resolved نه وي، یا اوسنی source موقتا unavailable وي.</td></tr><tr><td>Address language غلطه ده</td><td>IP geolocation language وګورئ او ډاډه شئ داسې source configured دی چې هغه language ملاتړ کوي.</td></tr><tr><td>Address د data center ښيي</td><td>ډېر proxies، cloud servers او crawlers د data center یا ISP addresses په توګه ښکاري.</td></tr><tr><td>Upload count لوړ دی</td><td>دا IP په دقت وګورئ او د اړتیا پر وخت uploads block کړئ.</td></tr><tr><td>Total upload size لوی دی</td><td>sort یا filter وکړئ، IP expand کړئ او مشخص files inspect کړئ.</td></tr><tr><td>له blocking وروسته restore ته اړتیا ده</td><td><code>Upload allowed</code> بېرته on کړئ.</td></tr></tbody></table><h2 id="چټک-بهیر" tabindex="-1">چټک بهیر <a class="header-anchor" href="#چټک-بهیر" aria-label="Permalink to &quot;چټک بهیر&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open IP Geolocation in Other Settings</span></span>
<span class="line"><span>-&gt; Choose IP geolocation language</span></span>
<span class="line"><span>-&gt; Fill MaxMind, Tencent Map, or ipapi credentials as needed</span></span>
<span class="line"><span>-&gt; Save settings</span></span>
<span class="line"><span>-&gt; Open User Management</span></span>
<span class="line"><span>-&gt; Review IP source, address, total upload size, and upload count</span></span>
<span class="line"><span>-&gt; Use search, sort, or advanced filters to find abnormal IPs</span></span>
<span class="line"><span>-&gt; Allow or block uploads as needed</span></span></code></pre></div>`,64)])])}const v=d(c,[["render",u]]);export{I as __pageData,v as default};
